import React from 'react';
import { PokemonWithStats } from '../types/pokemonChampions';
import { XIcon, ArrowDownIcon } from '@heroicons/react/outline';

interface PokemonPartyPanelProps {
  party: (PokemonWithStats | null)[];
  onRemoveFromParty: (index: number) => void;
  onSwapInParty: (index: number) => void;
  isSwapMode: boolean;
}

const PokemonPartyPanel: React.FC<PokemonPartyPanelProps> = ({ 
  party, 
  onRemoveFromParty, 
  onSwapInParty,
  isSwapMode 
}) => {
  const getPokemonImageUrl = (name: string, dexNumber: number) => {
    return `https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/${dexNumber}.png`;
  };

  const typeColors: Record<string, string> = {
    Normal: 'bg-gray-400',
    Fire: 'bg-red-500',
    Water: 'bg-blue-500',
    Electric: 'bg-yellow-400',
    Grass: 'bg-green-500',
    Ice: 'bg-cyan-400',
    Fighting: 'bg-red-700',
    Poison: 'bg-purple-500',
    Ground: 'bg-yellow-600',
    Flying: 'bg-indigo-400',
    Psychic: 'bg-pink-500',
    Bug: 'bg-lime-500',
    Rock: 'bg-yellow-700',
    Ghost: 'bg-purple-700',
    Dragon: 'bg-indigo-600',
    Dark: 'bg-gray-800',
    Steel: 'bg-gray-600',
    Fairy: 'bg-pink-400',
  };

  return (
    <div className="bg-white rounded-lg shadow-md p-3 mb-4 sticky top-0 z-10">
      <h2 className="text-base font-semibold mb-3 text-center">Your Pokemon Party</h2>
      <div className="grid grid-cols-3 gap-2 max-w-2xl mx-auto">
        {party.map((pokemon, index) => (
          <div
            key={index}
            className="relative bg-gray-50 border-2 border-dashed border-gray-300 rounded-lg p-2 min-h-[100px] flex flex-col items-center justify-center hover:border-blue-400 transition-colors"
          >
            {pokemon ? (
              <>
                <div className="absolute top-1 right-1 flex gap-1">
                  <button
                    onClick={() => onSwapInParty(index)}
                    className={`p-1 rounded transition-colors ${
                      isSwapMode 
                        ? 'bg-blue-500 text-white hover:bg-blue-600' 
                        : 'bg-gray-200 text-gray-600 hover:bg-gray-300'
                    }`}
                    title={isSwapMode ? 'Swap Pokemon' : 'Enter Swap Mode'}
                  >
                    <ArrowDownIcon className="w-3 h-3" />
                  </button>
                  <button
                    onClick={() => onRemoveFromParty(index)}
                    className="p-1 bg-red-500 text-white rounded hover:bg-red-600 transition-colors"
                    title="Remove from Party"
                  >
                    <XIcon className="w-3 h-3" />
                  </button>
                </div>

                <img
                  src={getPokemonImageUrl(pokemon.champion.name, pokemon.champion.dexNumber)}
                  alt={pokemon.champion.name}
                  className="w-12 h-12 object-contain mb-1"
                  onError={(e) => {
                    (e.target as HTMLImageElement).src = 'https://via.placeholder.com/48x48?text=?';
                  }}
                />

                <div className="text-center">
                  <div className="text-xs font-semibold truncate w-full">
                    {pokemon.champion.name}
                  </div>
                  <div className="flex flex-wrap gap-1 justify-center">
                    {pokemon.champion.types.slice(0, 2).map((type, typeIndex) => (
                      <span
                        key={typeIndex}
                        className={`px-1 py-0.5 text-xs text-white rounded-full ${typeColors[type] || 'bg-gray-400'}`}
                      >
                        {type.charAt(0)}
                      </span>
                    ))}
                  </div>
                </div>
              </>
            ) : (
              <div className="text-center text-gray-400">
                <div className="text-2xl mb-1">+</div>
                <div className="text-xs">Empty</div>
              </div>
            )}
          </div>
        ))}
      </div>

      {isSwapMode && (
        <div className="mt-2 text-center text-sm text-blue-600 font-medium">
          Click a Pokemon below to swap with selected slot
        </div>
      )}
    </div>
  );
};

export default PokemonPartyPanel;
